APP_CODE = '\nimport os\nimport shutil\nfrom datetime import date, datetime\nfrom urllib.parse import quote\n\nimport pandas as pd\nimport streamlit as st\n\n\n# ==========================================================\n# CONFIGURAÇÃO\n# ==========================================================\n\nst.set_page_config(\n    page_title="Sistema de Cotações Marialva",\n    page_icon="🛒",\n    layout="wide",\n    initial_sidebar_state="collapsed",\n)\n\nPASTA_DADOS = "dados"\nPASTA_BACKUPS = "backups"\n\nARQUIVOS = {\n    "produtos": os.path.join(PASTA_DADOS, "produtos.csv"),\n    "fornecedores": os.path.join(PASTA_DADOS, "fornecedores.csv"),\n    "cotacoes": os.path.join(PASTA_DADOS, "cotacoes.csv"),\n    "itens_cotacao": os.path.join(PASTA_DADOS, "itens_cotacao.csv"),\n    "respostas": os.path.join(PASTA_DADOS, "respostas.csv"),\n}\n\nCOLUNAS = {\n    "produtos": ["ProdutoID", "Produto", "Marca", "Tamanho", "Categoria", "Unidade", "Ativo", "Observacao"],\n    "fornecedores": ["FornecedorID", "Vendedor", "Empresa", "WhatsApp", "CategoriaForte", "Ativo", "Observacao"],\n    "cotacoes": ["CotacaoID", "Data", "Prazo", "Status", "Responsavel", "Observacao"],\n    "itens_cotacao": ["ItemID", "CotacaoID", "ProdutoID", "QuantidadeDesejada", "Observacao"],\n    "respostas": ["RespostaID", "CotacaoID", "FornecedorID", "ProdutoID", "Preco", "TemProduto", "Observacao"],\n}\n\n\n# ==========================================================\n# ESTILO VISUAL V4\n# ==========================================================\n\nst.markdown(\n    """\n    <style>\n    :root {\n        --bg: #0d1117;\n        --panel: #111827;\n        --panel-2: #0f172a;\n        --text: #f8fafc;\n        --muted: #94a3b8;\n        --line: rgba(148, 163, 184, 0.18);\n        --blue: #38bdf8;\n        --orange: #fb923c;\n        --green: #22c55e;\n        --purple: #a78bfa;\n        --pink: #f472b6;\n        --yellow: #facc15;\n        --red: #ef4444;\n    }\n\n    .block-container {\n        padding-top: 2rem;\n        padding-bottom: 3rem;\n        max-width: 1240px;\n    }\n\n    [data-testid="stSidebar"] {\n        display: none;\n    }\n\n    .top-hero {\n        padding: 26px 28px;\n        border-radius: 28px;\n        background:\n            radial-gradient(circle at 15% 20%, rgba(56, 189, 248, 0.22), transparent 28%),\n            radial-gradient(circle at 85% 15%, rgba(167, 139, 250, 0.22), transparent 28%),\n            linear-gradient(135deg, rgba(15, 23, 42, 0.98), rgba(17, 24, 39, 0.96));\n        border: 1px solid rgba(148, 163, 184, 0.18);\n        box-shadow: 0 20px 55px rgba(0,0,0,0.25);\n        margin-bottom: 22px;\n    }\n\n    .hero-title {\n        font-size: 2.35rem;\n        font-weight: 900;\n        letter-spacing: -0.04em;\n        margin: 0;\n        color: #ffffff;\n    }\n\n    .hero-subtitle {\n        color: var(--muted);\n        font-size: 1rem;\n        margin-top: 8px;\n        margin-bottom: 0;\n    }\n\n    .step-strip {\n        display: flex;\n        gap: 10px;\n        flex-wrap: wrap;\n        margin-top: 18px;\n    }\n\n    .step-pill {\n        display: inline-flex;\n        align-items: center;\n        gap: 8px;\n        padding: 8px 12px;\n        border-radius: 999px;\n        border: 1px solid rgba(148, 163, 184, 0.18);\n        background: rgba(15, 23, 42, 0.76);\n        color: #e2e8f0;\n        font-size: 0.9rem;\n        font-weight: 700;\n    }\n\n    .section-title {\n        font-size: 1.65rem;\n        font-weight: 900;\n        letter-spacing: -0.03em;\n        margin: 18px 0 10px 0;\n    }\n\n    .muted {\n        color: var(--muted);\n    }\n\n    .action-card {\n        min-height: 158px;\n        padding: 22px 22px 18px 22px;\n        border-radius: 24px;\n        border: 1px solid rgba(148, 163, 184, 0.18);\n        background: linear-gradient(180deg, rgba(17, 24, 39, 0.96), rgba(15, 23, 42, 0.94));\n        box-shadow: 0 14px 36px rgba(0,0,0,0.20);\n        position: relative;\n        overflow: hidden;\n        margin-bottom: 10px;\n    }\n\n    .action-card:before {\n        content: "";\n        position: absolute;\n        inset: 0 auto 0 0;\n        width: 7px;\n        background: var(--card-color);\n        box-shadow: 0 0 22px var(--card-color);\n    }\n\n    .card-icon {\n        width: 52px;\n        height: 52px;\n        border-radius: 18px;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        font-size: 1.65rem;\n        background: color-mix(in srgb, var(--card-color) 22%, transparent);\n        border: 1px solid color-mix(in srgb, var(--card-color) 46%, transparent);\n        margin-bottom: 12px;\n    }\n\n    .card-title {\n        font-size: 1.18rem;\n        font-weight: 900;\n        color: #fff;\n        margin: 0 0 6px 0;\n    }\n\n    .card-text {\n        color: #cbd5e1;\n        margin: 0;\n        font-size: 0.95rem;\n        line-height: 1.4;\n    }\n\n    .metric-card {\n        padding: 18px;\n        border-radius: 22px;\n        border: 1px solid rgba(148, 163, 184, 0.18);\n        background: rgba(15, 23, 42, 0.88);\n        min-height: 120px;\n    }\n\n    .metric-label {\n        color: var(--muted);\n        font-size: 0.92rem;\n        font-weight: 800;\n        margin-bottom: 7px;\n    }\n\n    .metric-value {\n        color: white;\n        font-size: 2.15rem;\n        font-weight: 900;\n        line-height: 1;\n    }\n\n    .status-open {\n        display: inline-block;\n        padding: 4px 10px;\n        border-radius: 999px;\n        background: rgba(250, 204, 21, 0.16);\n        color: #fde68a;\n        font-weight: 800;\n        border: 1px solid rgba(250, 204, 21, 0.25);\n    }\n\n    .status-final {\n        display: inline-block;\n        padding: 4px 10px;\n        border-radius: 999px;\n        background: rgba(34, 197, 94, 0.16);\n        color: #86efac;\n        font-weight: 800;\n        border: 1px solid rgba(34, 197, 94, 0.25);\n    }\n\n    .status-wait {\n        display: inline-block;\n        padding: 4px 10px;\n        border-radius: 999px;\n        background: rgba(251, 146, 60, 0.16);\n        color: #fed7aa;\n        font-weight: 800;\n        border: 1px solid rgba(251, 146, 60, 0.25);\n    }\n\n    .soft-box {\n        padding: 18px;\n        border-radius: 22px;\n        border: 1px solid rgba(148, 163, 184, 0.18);\n        background: rgba(15, 23, 42, 0.72);\n        margin-bottom: 14px;\n    }\n\n    div.stButton > button {\n        border-radius: 14px;\n        font-weight: 850;\n        min-height: 45px;\n        border: 1px solid rgba(148, 163, 184, 0.28);\n    }\n\n    div.stButton > button:hover {\n        transform: translateY(-1px);\n        transition: 0.15s ease;\n        border-color: rgba(56, 189, 248, 0.8);\n    }\n\n    .vendor-header {\n        padding: 22px;\n        border-radius: 26px;\n        background: linear-gradient(135deg, rgba(34, 197, 94, 0.20), rgba(56, 189, 248, 0.16), rgba(15, 23, 42, 0.96));\n        border: 1px solid rgba(148, 163, 184, 0.22);\n        margin-bottom: 20px;\n    }\n\n    .vendor-title {\n        font-size: 2rem;\n        font-weight: 900;\n        letter-spacing: -0.03em;\n    }\n\n    .item-line {\n        padding: 14px 16px;\n        border-radius: 18px;\n        border: 1px solid rgba(148, 163, 184, 0.16);\n        background: rgba(15, 23, 42, 0.70);\n        margin-bottom: 12px;\n    }\n\n    hr {\n        border-color: rgba(148, 163, 184, 0.16);\n    }\n    </style>\n    """,\n    unsafe_allow_html=True,\n)\n\n\n# ==========================================================\n# FUNÇÕES DE DADOS\n# ==========================================================\n\ndef criar_arquivos_iniciais():\n    os.makedirs(PASTA_DADOS, exist_ok=True)\n    os.makedirs(PASTA_BACKUPS, exist_ok=True)\n\n    for nome, caminho in ARQUIVOS.items():\n        if not os.path.exists(caminho):\n            pd.DataFrame(columns=COLUNAS[nome]).to_csv(caminho, index=False, encoding="utf-8-sig")\n\n\ndef carregar(nome):\n    criar_arquivos_iniciais()\n    df = pd.read_csv(ARQUIVOS[nome], encoding="utf-8-sig", dtype=str).fillna("")\n    for coluna in COLUNAS[nome]:\n        if coluna not in df.columns:\n            df[coluna] = ""\n    return df[COLUNAS[nome]]\n\n\ndef salvar(nome, df):\n    df = df.copy()\n    for coluna in COLUNAS[nome]:\n        if coluna not in df.columns:\n            df[coluna] = ""\n    df[COLUNAS[nome]].to_csv(ARQUIVOS[nome], index=False, encoding="utf-8-sig")\n\n\ndef gerar_id(prefixo, df, coluna_id):\n    if df.empty or coluna_id not in df.columns:\n        return f"{prefixo}001"\n\n    ids = df[coluna_id].astype(str).str.replace(prefixo, "", regex=False)\n    numeros = pd.to_numeric(ids, errors="coerce").dropna()\n    proximo = int(numeros.max()) + 1 if not numeros.empty else 1\n    return f"{prefixo}{proximo:03d}"\n\n\ndef parse_preco(valor):\n    if valor is None:\n        return None\n    texto = str(valor).strip().upper()\n    if texto in ["", "NT", "N/T", "NAO TEM", "NÃO TEM", "-"]:\n        return None\n    texto = texto.replace("R$", "").replace(" ", "")\n    texto = texto.replace(".", "").replace(",", ".")\n    try:\n        return float(texto)\n    except Exception:\n        return None\n\n\ndef moeda(valor):\n    try:\n        return f"R$ {float(valor):,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")\n    except Exception:\n        return "R$ 0,00"\n\n\ndef descricao_produto(row):\n    partes = [str(row.get("Produto", "")).strip(), str(row.get("Marca", "")).strip(), str(row.get("Tamanho", "")).strip()]\n    return " ".join([p for p in partes if p and p.lower() != "nan"]).strip()\n\n\ndef recarregar_bases():\n    return {\n        "produtos": carregar("produtos"),\n        "fornecedores": carregar("fornecedores"),\n        "cotacoes": carregar("cotacoes"),\n        "itens": carregar("itens_cotacao"),\n        "respostas": carregar("respostas"),\n    }\n\n\ndef query_param(nome):\n    try:\n        valor = st.query_params.get(nome, "")\n        if isinstance(valor, list):\n            return valor[0] if valor else ""\n        return valor or ""\n    except Exception:\n        return ""\n\n\ndef set_tela(nome):\n    st.session_state.tela = nome\n    st.rerun()\n\n\ndef voltar_painel():\n    if st.button("← Voltar ao painel", use_container_width=False):\n        set_tela("painel")\n\n\ndef hero():\n    st.markdown(\n        """\n        <div class="top-hero">\n            <p class="hero-title">🛒 Sistema de Cotações Marialva</p>\n            <p class="hero-subtitle">Fluxo visual: criar lista → enviar aos vendedores → receber preços → comparar → comprar melhor.</p>\n            <div class="step-strip">\n                <span class="step-pill">1. 📦 Criar</span>\n                <span class="step-pill">2. 📲 Enviar</span>\n                <span class="step-pill">3. ✅ Receber</span>\n                <span class="step-pill">4. 💰 Comparar</span>\n                <span class="step-pill">5. 🛒 Comprar</span>\n            </div>\n        </div>\n        """,\n        unsafe_allow_html=True,\n    )\n\n\ndef action_card(icon, title, text, color):\n    st.markdown(\n        f"""\n        <div class="action-card" style="--card-color:{color};">\n            <div class="card-icon">{icon}</div>\n            <p class="card-title">{title}</p>\n            <p class="card-text">{text}</p>\n        </div>\n        """,\n        unsafe_allow_html=True,\n    )\n\n\ndef metric_box(label, value):\n    st.markdown(\n        f"""\n        <div class="metric-card">\n            <div class="metric-label">{label}</div>\n            <div class="metric-value">{value}</div>\n        </div>\n        """,\n        unsafe_allow_html=True,\n    )\n\n\ndef status_html(status):\n    s = str(status).strip().lower()\n    if "final" in s:\n        return \'<span class="status-final">Finalizada</span>\'\n    if "aguard" in s or "parcial" in s:\n        return \'<span class="status-wait">Aguardando</span>\'\n    return \'<span class="status-open">Aberta</span>\'\n\n\ndef cotacoes_opcoes(cotacoes):\n    if cotacoes.empty:\n        return []\n    return (cotacoes["CotacaoID"].astype(str) + " — " + cotacoes["Observacao"].astype(str)).tolist()\n\n\ndef extrair_id(opcao):\n    return str(opcao).split(" — ")[0].strip().split(" - ")[0].strip()\n\n\ndef calcular_vencedores(cotacao_id=None):\n    bases = recarregar_bases()\n    produtos = bases["produtos"]\n    fornecedores = bases["fornecedores"]\n    respostas = bases["respostas"].copy()\n\n    if respostas.empty:\n        return pd.DataFrame()\n\n    if cotacao_id:\n        respostas = respostas[respostas["CotacaoID"].astype(str) == str(cotacao_id)]\n\n    respostas["PrecoNum"] = respostas["Preco"].apply(parse_preco)\n    respostas = respostas[(respostas["TemProduto"].astype(str).str.lower() == "sim") & respostas["PrecoNum"].notna()]\n\n    if respostas.empty:\n        return pd.DataFrame()\n\n    df = respostas.merge(produtos, on="ProdutoID", how="left").merge(fornecedores, on="FornecedorID", how="left")\n\n    idx = df.groupby(["CotacaoID", "ProdutoID"])["PrecoNum"].idxmin()\n    vencedores = df.loc[idx].copy()\n\n    maiores = df.groupby(["CotacaoID", "ProdutoID"])["PrecoNum"].max().reset_index().rename(columns={"PrecoNum": "MaiorPreco"})\n    vencedores = vencedores.merge(maiores, on=["CotacaoID", "ProdutoID"], how="left")\n    vencedores["EconomiaUnitaria"] = vencedores["MaiorPreco"] - vencedores["PrecoNum"]\n    vencedores["DescricaoProduto"] = vencedores.apply(descricao_produto, axis=1)\n\n    return vencedores\n\n\n# ==========================================================\n# ÁREA DO VENDEDOR\n# ==========================================================\n\ndef tela_vendedor(cotacao_id, fornecedor_id):\n    bases = recarregar_bases()\n    produtos = bases["produtos"]\n    fornecedores = bases["fornecedores"]\n    cotacoes = bases["cotacoes"]\n    itens = bases["itens"]\n    respostas = bases["respostas"]\n\n    cot = cotacoes[cotacoes["CotacaoID"].astype(str) == str(cotacao_id)]\n    forn = fornecedores[fornecedores["FornecedorID"].astype(str) == str(fornecedor_id)]\n\n    if cot.empty or forn.empty:\n        st.error("Link inválido ou cotação não encontrada.")\n        return\n\n    cot = cot.iloc[0]\n    forn = forn.iloc[0]\n\n    st.markdown(\n        f"""\n        <div class="vendor-header">\n            <div class="vendor-title">Cotação Marialva</div>\n            <div class="muted">Fornecedor: <b>{forn[\'Vendedor\']}</b> • Cotação: <b>{cotacao_id}</b> • Prazo: <b>{cot[\'Prazo\']}</b></div>\n        </div>\n        """,\n        unsafe_allow_html=True,\n    )\n\n    itens_cot = itens[itens["CotacaoID"].astype(str) == str(cotacao_id)].merge(produtos, on="ProdutoID", how="left")\n\n    if itens_cot.empty:\n        st.warning("Essa cotação ainda não possui itens.")\n        return\n\n    st.info("Preencha os preços dos itens disponíveis. Se não tiver o produto, desmarque a opção \'Tenho\'.")\n\n    with st.form("form_vendedor"):\n        respostas_temp = []\n        for _, row in itens_cot.iterrows():\n            pid = str(row["ProdutoID"])\n            nome = descricao_produto(row)\n            qtd = row.get("QuantidadeDesejada", "")\n            st.markdown(\n                f"""\n                <div class="item-line">\n                    <b>{nome}</b><br>\n                    <span class="muted">Código: {pid} • Quantidade solicitada: {qtd}</span>\n                </div>\n                """,\n                unsafe_allow_html=True,\n            )\n\n            col1, col2 = st.columns([1, 2])\n            with col1:\n                tenho = st.checkbox("Tenho", value=True, key=f"tenho_{pid}")\n            with col2:\n                preco = st.text_input("Preço", placeholder="Ex: 9,15", key=f"preco_{pid}")\n\n            respostas_temp.append((pid, tenho, preco))\n\n        enviar = st.form_submit_button("✅ Enviar cotação", use_container_width=True)\n\n        if enviar:\n            # Remove respostas anteriores desse fornecedor para essa cotação, evitando duplicidade.\n            respostas = respostas[\n                ~(\n                    (respostas["CotacaoID"].astype(str) == str(cotacao_id))\n                    & (respostas["FornecedorID"].astype(str) == str(fornecedor_id))\n                )\n            ].copy()\n\n            novas = []\n            for pid, tenho, preco_txt in respostas_temp:\n                preco_num = parse_preco(preco_txt)\n                tem_produto = "Sim" if tenho and preco_num is not None else "Não"\n                novo_id = gerar_id("RESP", pd.concat([respostas, pd.DataFrame(novas)], ignore_index=True), "RespostaID")\n                novas.append(\n                    {\n                        "RespostaID": novo_id,\n                        "CotacaoID": cotacao_id,\n                        "FornecedorID": fornecedor_id,\n                        "ProdutoID": pid,\n                        "Preco": str(preco_num).replace(".", ",") if preco_num is not None else "",\n                        "TemProduto": tem_produto,\n                        "Observacao": "Resposta enviada pelo link do vendedor",\n                    }\n                )\n\n            respostas = pd.concat([respostas, pd.DataFrame(novas)], ignore_index=True)\n            salvar("respostas", respostas)\n            st.success("Cotação enviada com sucesso. Obrigado!")\n\n\n# ==========================================================\n# PAINEL INTERNO\n# ==========================================================\n\ndef tela_painel():\n    bases = recarregar_bases()\n    produtos = bases["produtos"]\n    fornecedores = bases["fornecedores"]\n    cotacoes = bases["cotacoes"]\n    respostas = bases["respostas"]\n\n    hero()\n\n    c1, c2, c3, c4 = st.columns(4)\n    with c1:\n        metric_box("Produtos", len(produtos))\n    with c2:\n        metric_box("Fornecedores", len(fornecedores))\n    with c3:\n        metric_box("Cotações", len(cotacoes))\n    with c4:\n        metric_box("Respostas", len(respostas))\n\n    st.markdown(\'<p class="section-title">Escolha uma ação</p>\', unsafe_allow_html=True)\n\n    col1, col2, col3 = st.columns(3)\n\n    with col1:\n        action_card("📦", "Criar cotação", "Monte uma lista de produtos para cotar.", "#38bdf8")\n        if st.button("Criar cotação", key="go_criar", use_container_width=True):\n            set_tela("criar")\n\n    with col2:\n        action_card("📲", "Enviar aos vendedores", "Gere links simples para WhatsApp.", "#fb923c")\n        if st.button("Enviar links", key="go_enviar", use_container_width=True):\n            set_tela("enviar")\n\n    with col3:\n        action_card("✅", "Ver respostas", "Acompanhe quem já respondeu.", "#22c55e")\n        if st.button("Ver respostas", key="go_respostas", use_container_width=True):\n            set_tela("respostas")\n\n    col4, col5, col6 = st.columns(3)\n\n    with col4:\n        action_card("💰", "Comparar preços", "Veja o menor preço por item.", "#a78bfa")\n        if st.button("Comparar", key="go_comparar", use_container_width=True):\n            set_tela("comparar")\n\n    with col5:\n        action_card("🛒", "Pedido final", "Separe o pedido por vendedor.", "#f472b6")\n        if st.button("Gerar pedido", key="go_pedido", use_container_width=True):\n            set_tela("pedido")\n\n    with col6:\n        action_card("⚙️", "Cadastros", "Produtos, fornecedores e backup.", "#facc15")\n        if st.button("Abrir cadastros", key="go_cadastros", use_container_width=True):\n            set_tela("cadastros")\n\n    st.markdown(\'<p class="section-title">Últimas cotações</p>\', unsafe_allow_html=True)\n\n    if cotacoes.empty:\n        st.info("Nenhuma cotação criada ainda.")\n    else:\n        ult = cotacoes.tail(6).copy()\n        st.dataframe(ult, use_container_width=True, hide_index=True)\n\n\ndef tela_criar():\n    hero()\n    voltar_painel()\n    st.markdown(\'<p class="section-title">📦 Criar ou montar cotação</p>\', unsafe_allow_html=True)\n\n    bases = recarregar_bases()\n    produtos = bases["produtos"]\n    cotacoes = bases["cotacoes"]\n    itens = bases["itens"]\n\n    with st.expander("➕ Criar nova cotação", expanded=True):\n        with st.form("nova_cotacao"):\n            c1, c2, c3 = st.columns(3)\n            with c1:\n                data_cotacao = st.date_input("Data", value=date.today())\n            with c2:\n                prazo = st.text_input("Prazo", value="Hoje até 15h")\n            with c3:\n                responsavel = st.text_input("Responsável", value="João")\n\n            obs = st.text_input("Nome/observação da cotação", placeholder="Ex: Cotação de mercearia")\n            criar = st.form_submit_button("Criar cotação")\n\n            if criar:\n                novo_id = gerar_id("COT", cotacoes, "CotacaoID")\n                novo = pd.DataFrame([{\n                    "CotacaoID": novo_id,\n                    "Data": str(data_cotacao),\n                    "Prazo": prazo,\n                    "Status": "Aberta",\n                    "Responsavel": responsavel,\n                    "Observacao": obs or f"Cotação {novo_id}",\n                }])\n                salvar("cotacoes", pd.concat([cotacoes, novo], ignore_index=True))\n                st.success(f"Cotação criada: {novo_id}")\n                st.rerun()\n\n    cotacoes = carregar("cotacoes")\n    if cotacoes.empty:\n        st.warning("Crie uma cotação para adicionar itens.")\n        return\n\n    st.markdown("### Adicionar produtos à cotação")\n\n    cotacao_opcao = st.selectbox("Cotação", cotacoes_opcoes(cotacoes))\n    cotacao_id = extrair_id(cotacao_opcao)\n\n    if produtos.empty:\n        st.warning("Nenhum produto cadastrado.")\n        return\n\n    busca = st.text_input("Buscar produto", placeholder="Digite parte do nome, marca ou tamanho")\n    produtos_filtrados = produtos.copy()\n    if busca:\n        mask = produtos_filtrados.apply(lambda row: busca.lower() in " ".join(row.astype(str)).lower(), axis=1)\n        produtos_filtrados = produtos_filtrados[mask]\n\n    produtos_filtrados["Label"] = produtos_filtrados.apply(\n        lambda row: f"{row[\'ProdutoID\']} — {descricao_produto(row)}", axis=1\n    )\n\n    selecionados = st.multiselect(\n        "Escolha os produtos",\n        produtos_filtrados["Label"].tolist(),\n        placeholder="Selecione os itens da cotação",\n    )\n\n    colq, colo = st.columns([1, 3])\n    with colq:\n        qtd_padrao = st.number_input("Qtd padrão", min_value=0, value=1, step=1)\n    with colo:\n        obs_item = st.text_input("Observação para esses itens", placeholder="Opcional")\n\n    if st.button("Adicionar selecionados", use_container_width=True):\n        if not selecionados:\n            st.warning("Selecione pelo menos um produto.")\n        else:\n            novos = []\n            itens_atual = carregar("itens_cotacao")\n            existentes = set(\n                itens_atual[itens_atual["CotacaoID"].astype(str) == cotacao_id]["ProdutoID"].astype(str).tolist()\n            )\n            base_temp = itens_atual.copy()\n\n            for label in selecionados:\n                pid = extrair_id(label)\n                if pid in existentes:\n                    continue\n                item_id = gerar_id("ITEM", pd.concat([base_temp, pd.DataFrame(novos)], ignore_index=True), "ItemID")\n                novos.append({\n                    "ItemID": item_id,\n                    "CotacaoID": cotacao_id,\n                    "ProdutoID": pid,\n                    "QuantidadeDesejada": qtd_padrao,\n                    "Observacao": obs_item,\n                })\n\n            if novos:\n                salvar("itens_cotacao", pd.concat([itens_atual, pd.DataFrame(novos)], ignore_index=True))\n                st.success(f"{len(novos)} item(ns) adicionados à cotação.")\n                st.rerun()\n            else:\n                st.info("Os produtos selecionados já estavam nessa cotação.")\n\n    st.markdown("### Itens desta cotação")\n    itens = carregar("itens_cotacao")\n    itens_cot = itens[itens["CotacaoID"].astype(str) == cotacao_id].merge(produtos, on="ProdutoID", how="left")\n    if itens_cot.empty:\n        st.info("Nenhum item nesta cotação ainda.")\n    else:\n        itens_cot["Descrição"] = itens_cot.apply(descricao_produto, axis=1)\n        st.dataframe(\n            itens_cot[["ItemID", "ProdutoID", "Descrição", "QuantidadeDesejada", "Observacao"]],\n            use_container_width=True,\n            hide_index=True,\n        )\n\n\ndef tela_enviar():\n    hero()\n    voltar_painel()\n    st.markdown(\'<p class="section-title">📲 Enviar cotação para vendedores</p>\', unsafe_allow_html=True)\n\n    bases = recarregar_bases()\n    cotacoes = bases["cotacoes"]\n    fornecedores = bases["fornecedores"]\n    itens = bases["itens"]\n    produtos = bases["produtos"]\n\n    if cotacoes.empty or fornecedores.empty:\n        st.warning("É necessário ter pelo menos uma cotação e fornecedores cadastrados.")\n        return\n\n    cotacao_id = extrair_id(st.selectbox("Cotação", cotacoes_opcoes(cotacoes)))\n    base_url = st.text_input("Link base do sistema", value="http://localhost:8501", help="Se estiver usando Ngrok, cole aqui o link https://...ngrok-free.dev")\n\n    st.markdown("### Links por vendedor")\n\n    fornecedores_ativos = fornecedores[fornecedores["Ativo"].astype(str).str.lower() != "não"].copy()\n    if fornecedores_ativos.empty:\n        fornecedores_ativos = fornecedores.copy()\n\n    itens_cot = itens[itens["CotacaoID"].astype(str) == cotacao_id].merge(produtos, on="ProdutoID", how="left")\n    qtd_itens = len(itens_cot)\n\n    for _, row in fornecedores_ativos.iterrows():\n        fornecedor_id = row["FornecedorID"]\n        vendedor = row["Vendedor"]\n        link = f"{base_url.rstrip(\'/\')}?cotacao={quote(str(cotacao_id))}&fornecedor={quote(str(fornecedor_id))}"\n        mensagem = f"""Bom dia, {vendedor}!\n\nSegue a cotação do Supermercado Marialva.\n\nPor favor, preencha os preços pelo link abaixo:\n{link}\n\nItens na cotação: {qtd_itens}\nPrazo: {cotacoes[cotacoes[\'CotacaoID\'].astype(str) == cotacao_id][\'Prazo\'].iloc[0]}\n\nObrigado."""\n\n        with st.expander(f"📲 {vendedor} — {fornecedor_id}", expanded=False):\n            st.text_area("Mensagem para WhatsApp", mensagem, height=185, key=f"msg_{fornecedor_id}")\n            st.code(link)\n\n\ndef tela_respostas():\n    hero()\n    voltar_painel()\n    st.markdown(\'<p class="section-title">✅ Respostas dos vendedores</p>\', unsafe_allow_html=True)\n\n    bases = recarregar_bases()\n    cotacoes = bases["cotacoes"]\n    fornecedores = bases["fornecedores"]\n    respostas = bases["respostas"]\n\n    if cotacoes.empty:\n        st.warning("Nenhuma cotação criada.")\n        return\n\n    cotacao_id = extrair_id(st.selectbox("Cotação", cotacoes_opcoes(cotacoes)))\n\n    resp_cot = respostas[respostas["CotacaoID"].astype(str) == cotacao_id].copy()\n    if resp_cot.empty:\n        st.info("Nenhuma resposta lançada para essa cotação.")\n        return\n\n    qtd_por_fornecedor = resp_cot.groupby("FornecedorID")["ProdutoID"].count().reset_index(name="Itens respondidos")\n    qtd_por_fornecedor = qtd_por_fornecedor.merge(fornecedores, on="FornecedorID", how="left")\n\n    st.markdown("### Quem respondeu")\n    st.dataframe(\n        qtd_por_fornecedor[["FornecedorID", "Vendedor", "Empresa", "Itens respondidos"]],\n        use_container_width=True,\n        hide_index=True,\n    )\n\n    st.markdown("### Respostas detalhadas")\n    st.dataframe(resp_cot, use_container_width=True, hide_index=True)\n\n\ndef tela_comparar():\n    hero()\n    voltar_painel()\n    st.markdown(\'<p class="section-title">💰 Comparar preços</p>\', unsafe_allow_html=True)\n\n    cotacoes = carregar("cotacoes")\n    if cotacoes.empty:\n        st.warning("Nenhuma cotação criada.")\n        return\n\n    cotacao_id = extrair_id(st.selectbox("Cotação", cotacoes_opcoes(cotacoes)))\n    vencedores = calcular_vencedores(cotacao_id)\n\n    if vencedores.empty:\n        st.info("Ainda não há preços válidos para comparar nessa cotação.")\n        return\n\n    resultado = vencedores[[\n        "CotacaoID", "ProdutoID", "DescricaoProduto", "Categoria", "Vendedor", "PrecoNum", "MaiorPreco", "EconomiaUnitaria"\n    ]].rename(columns={\n        "DescricaoProduto": "Produto",\n        "Vendedor": "Fornecedor vencedor",\n        "PrecoNum": "Menor preço",\n        "MaiorPreco": "Maior preço",\n        "EconomiaUnitaria": "Economia un.",\n    })\n\n    st.dataframe(resultado, use_container_width=True, hide_index=True)\n\n    c1, c2 = st.columns(2)\n    with c1:\n        metric_box("Itens com vencedor", len(resultado))\n    with c2:\n        metric_box("Economia unitária total", moeda(resultado["Economia un."].sum()))\n\n\ndef tela_pedido():\n    hero()\n    voltar_painel()\n    st.markdown(\'<p class="section-title">🛒 Pedido final por fornecedor</p>\', unsafe_allow_html=True)\n\n    cotacoes = carregar("cotacoes")\n    if cotacoes.empty:\n        st.warning("Nenhuma cotação criada.")\n        return\n\n    cotacao_id = extrair_id(st.selectbox("Cotação", cotacoes_opcoes(cotacoes)))\n    vencedores = calcular_vencedores(cotacao_id)\n\n    if vencedores.empty:\n        st.info("Ainda não há vencedores para gerar pedido.")\n        return\n\n    for vendedor, grupo in vencedores.groupby("Vendedor"):\n        st.markdown(f"### {vendedor}")\n        linhas = []\n        for _, row in grupo.iterrows():\n            linhas.append(f"- {row[\'DescricaoProduto\']} — {moeda(row[\'PrecoNum\'])}")\n\n        texto = "\\n".join(linhas)\n        st.text_area(f"Pedido para {vendedor}", texto, height=150, key=f"pedido_{vendedor}")\n\n\ndef tela_cadastros():\n    hero()\n    voltar_painel()\n    st.markdown(\'<p class="section-title">⚙️ Cadastros e manutenção</p>\', unsafe_allow_html=True)\n\n    aba = st.tabs(["📦 Produtos", "🚚 Fornecedores", "🛡️ Backups", "🗂️ Bases"])\n\n    with aba[0]:\n        produtos = carregar("produtos")\n        st.markdown("### Cadastrar produto")\n        with st.form("form_produto_v4"):\n            c1, c2, c3 = st.columns(3)\n            with c1:\n                produto = st.text_input("Produto", placeholder="Ex: Atum sólido")\n                marca = st.text_input("Marca", placeholder="Ex: Coqueiro")\n            with c2:\n                tamanho = st.text_input("Tamanho", placeholder="Ex: 170g")\n                categoria = st.text_input("Categoria", value="Mercearia")\n            with c3:\n                unidade = st.text_input("Unidade", value="Unidade")\n                obs = st.text_input("Observação")\n\n            if st.form_submit_button("Salvar produto"):\n                novo_id = gerar_id("PROD", produtos, "ProdutoID")\n                novo = pd.DataFrame([{\n                    "ProdutoID": novo_id,\n                    "Produto": produto,\n                    "Marca": marca,\n                    "Tamanho": tamanho,\n                    "Categoria": categoria,\n                    "Unidade": unidade,\n                    "Ativo": "Sim",\n                    "Observacao": obs,\n                }])\n                salvar("produtos", pd.concat([produtos, novo], ignore_index=True))\n                st.success(f"Produto salvo: {novo_id}")\n                st.rerun()\n\n        st.markdown("### Editar produtos")\n        busca = st.text_input("Buscar nos produtos", key="busca_produtos")\n        df_edit = carregar("produtos")\n        if busca:\n            mask = df_edit.apply(lambda row: busca.lower() in " ".join(row.astype(str)).lower(), axis=1)\n            df_edit = df_edit[mask]\n\n        editado = st.data_editor(df_edit, use_container_width=True, hide_index=True, num_rows="dynamic", key="editor_produtos")\n        if st.button("Salvar alterações em produtos"):\n            # Se houver busca, atualiza apenas linhas exibidas.\n            produtos_total = carregar("produtos")\n            ids_editados = set(editado["ProdutoID"].astype(str))\n            produtos_total = produtos_total[~produtos_total["ProdutoID"].astype(str).isin(ids_editados)]\n            salvar("produtos", pd.concat([produtos_total, editado], ignore_index=True))\n            st.success("Produtos atualizados.")\n            st.rerun()\n\n    with aba[1]:\n        fornecedores = carregar("fornecedores")\n        st.markdown("### Cadastrar fornecedor")\n        with st.form("form_fornecedor_v4"):\n            c1, c2 = st.columns(2)\n            with c1:\n                vendedor = st.text_input("Vendedor", placeholder="Ex: Marcio")\n                empresa = st.text_input("Empresa")\n                whatsapp = st.text_input("WhatsApp")\n            with c2:\n                categoria = st.text_input("Categoria forte", value="Mercearia")\n                obs = st.text_input("Observação")\n\n            if st.form_submit_button("Salvar fornecedor"):\n                novo_id = gerar_id("FOR", fornecedores, "FornecedorID")\n                novo = pd.DataFrame([{\n                    "FornecedorID": novo_id,\n                    "Vendedor": vendedor,\n                    "Empresa": empresa,\n                    "WhatsApp": whatsapp,\n                    "CategoriaForte": categoria,\n                    "Ativo": "Sim",\n                    "Observacao": obs,\n                }])\n                salvar("fornecedores", pd.concat([fornecedores, novo], ignore_index=True))\n                st.success(f"Fornecedor salvo: {novo_id}")\n                st.rerun()\n\n        st.markdown("### Editar fornecedores")\n        fornecedores_edit = st.data_editor(carregar("fornecedores"), use_container_width=True, hide_index=True, num_rows="dynamic", key="editor_fornecedores")\n        if st.button("Salvar alterações em fornecedores"):\n            salvar("fornecedores", fornecedores_edit)\n            st.success("Fornecedores atualizados.")\n            st.rerun()\n\n    with aba[2]:\n        st.markdown("### Criar cópia de segurança")\n        st.write("Crie um backup dos arquivos do sistema antes de grandes alterações.")\n        if st.button("Criar backup agora"):\n            os.makedirs(PASTA_BACKUPS, exist_ok=True)\n            nome = datetime.now().strftime("backup_%Y%m%d_%H%M%S")\n            destino = os.path.join(PASTA_BACKUPS, nome)\n            os.makedirs(destino, exist_ok=True)\n\n            if os.path.exists(PASTA_DADOS):\n                shutil.copytree(PASTA_DADOS, os.path.join(destino, "dados"), dirs_exist_ok=True)\n            if os.path.exists("app.py"):\n                shutil.copy2("app.py", os.path.join(destino, "app.py"))\n\n            st.success(f"Backup criado em: {destino}")\n\n    with aba[3]:\n        base = st.selectbox("Escolha a base", list(ARQUIVOS.keys()))\n        st.dataframe(carregar(base), use_container_width=True, hide_index=True)\n\n\n# ==========================================================\n# ROTEAMENTO\n# ==========================================================\n\ncriar_arquivos_iniciais()\n\ncotacao_link = query_param("cotacao")\nfornecedor_link = query_param("fornecedor")\n\nif cotacao_link and fornecedor_link:\n    tela_vendedor(cotacao_link, fornecedor_link)\nelse:\n    if "tela" not in st.session_state:\n        st.session_state.tela = "painel"\n\n    paginas = {\n        "painel": tela_painel,\n        "criar": tela_criar,\n        "enviar": tela_enviar,\n        "respostas": tela_respostas,\n        "comparar": tela_comparar,\n        "pedido": tela_pedido,\n        "cadastros": tela_cadastros,\n    }\n\n    paginas.get(st.session_state.tela, tela_painel)()\n'

def main():
    app_path = Path("app.py")
    if app_path.exists():
        backup = Path(f"app_backup_{datetime.now().strftime('%Y%m%d_%H%M%S')}.py")
        backup.write_text(app_path.read_text(encoding="utf-8"), encoding="utf-8")
        print(f"Backup criado: {backup}")

    app_path.write_text(APP_CODE, encoding="utf-8")
    print("Interface V4 instalada com sucesso!")
    print("Agora rode: python -m streamlit run app.py")
    print("Depois atualize o navegador com F5.")

if __name__ == "__main__":
    main()
